// ===== 图象法七步主线 配置（三年级下册全知识点） =====

export type StepStatus = 'completed' | 'current' | 'locked';

export interface StepConfig {
  id: string;
  index: number;
  icon: string;
  label: string;
  subtitle: string;
  description: string;
  path: string;
  /** 步骤中是否允许出现公式 */
  formulaAllowed: boolean;
}

export interface TopicConfig {
  id: string;
  title: string;
  subtitle: string;
  icon: string;
  grade: string;
  /** 该知识点七步学习路径 */
  steps: StepConfig[];
}

// ===== 七步通用模板 =====
const STEP_META = [
  { id: 'touch',    icon: '✋', label: '摸一摸', formulaAllowed: false },
  { id: 'compare',  icon: '⚖️', label: '比一比', formulaAllowed: false },
  { id: 'count',    icon: '🔢', label: '数一数', formulaAllowed: false },
  { id: 'draw',     icon: '✏️', label: '画一画', formulaAllowed: false },
  { id: 'transform',icon: '🔄', label: '变一变', formulaAllowed: false },
  { id: 'apply',    icon: '🏠', label: '用一用', formulaAllowed: false },
  { id: 'discover', icon: '💡', label: '说一说', formulaAllowed: true  },
];

function buildSteps(
  topicId: string,
  defs: { subtitle: string; description: string }[]
): StepConfig[] {
  return STEP_META.map((meta, i) => ({
    id: meta.id,
    index: i + 1,
    icon: meta.icon,
    label: meta.label,
    subtitle: defs[i].subtitle,
    description: defs[i].description,
    path: `/learn/${topicId}/${meta.id}`,
    formulaAllowed: meta.formulaAllowed,
  }));
}

