// ===== 辅助函数 =====

/** 根据知识点 ID 获取知识点配置 */
export function getTopic(topicId: string): TopicConfig | undefined {
  return TOPICS.find((t) => t.id === topicId);
}

/** 根据知识点 ID 获取步骤列表 */
export function getTopicSteps(topicId: string): StepConfig[] {
  return getTopic(topicId)?.steps ?? [];
}

/** 根据知识点 ID 和步骤 ID 获取步骤配置 */
export function getStep(topicId: string, stepId: string): StepConfig | undefined {
  return getTopicSteps(topicId).find((s) => s.id === stepId);
}

/** 获取某一步的下一步（兼容旧版单参数调用） */
export function getNextStep(topicOrStepId: string, stepId?: string): StepConfig | null {
  const topicId = stepId === undefined ? 'area' : topicOrStepId;
  const currentStepId = stepId === undefined ? topicOrStepId : stepId;
  const steps = getTopicSteps(topicId);
  const idx = steps.findIndex((s) => s.id === currentStepId);
  if (idx < 0 || idx >= steps.length - 1) return null;
  return steps[idx + 1];
}

/** 获取某一步的上一步（兼容旧版单参数调用） */
export function getPrevStep(topicOrStepId: string, stepId?: string): StepConfig | null {
  const topicId = stepId === undefined ? 'area' : topicOrStepId;
  const currentStepId = stepId === undefined ? topicOrStepId : stepId;
  const steps = getTopicSteps(topicId);
  const idx = steps.findIndex((s) => s.id === currentStepId);
  if (idx <= 0) return null;
  return steps[idx - 1];
}
